package com.ywcode.resourceareanotifier;

import net.runelite.api.*;
import net.runelite.client.ui.overlay.*;

import javax.inject.*;
import java.awt.*;

public class ScreenNotificationOverlay extends OverlayPanel {

    private final Client client;

    @Inject
    private ScreenNotificationOverlay(Client client) {
        this.client = client;

        setPosition(OverlayPosition.DYNAMIC);
        //Alternatively use other OverlayLayers to e.g. not render on top of the inventory, chatbox, minimap etc
        setLayer(OverlayLayer.ALWAYS_ON_TOP);
    }

    @Override
    public Dimension render(Graphics2D graphics) {
        //If flash, set the color to flash
        if (ResourceAreaNotifierPlugin.getNotificationOverlay() == NotificationOverlay.Flash) {
            if (client.getGameCycle() % 40 >= 20) {
                graphics.setColor(ResourceAreaNotifierPlugin.getSolidFlashColor());
            } else {
                graphics.setColor(new Color(0, 0, 0, 0));
            }
        } else {
            //If solid
            graphics.setColor(ResourceAreaNotifierPlugin.getSolidFlashColor());
        }
        //Fill the rectangle using the client width and height
        graphics.fillRect(0, 0, client.getCanvasWidth(), client.getCanvasHeight());
        return null;
    }
}

package com.ywcode.resourceareanotifier;

//Uploaded to a separate branch of the plugin that only contains the .wav files
//PM Files cannot be updated without a filename or version change!
//PM Replace spaces with underscores in file names and add a version number, e.g. "_v1.0"
//Including a version in some file details can be difficult to get with default sound libraries probably, and calculating the CRC file hash on every plugin startup is probably less desirable
//Alternatively just create a new branch and change the URL in SoundFileManager

//PM 32-bit audio is not supported! The samples can be either 8-bit or 16-bit, with sampling rate from 8 kHz to 48 kHz.
//PM format of the filenames = Wake_Up_v1.0.wav
public enum Sound {
    DISABLED("Disabled", 1.0),
    WAKE_UP("Wake Up", 1.0),
    BADOOB("Badoob", 1.0),
    RPG_LEVEL_UP("RPG Level Up", 1.0),
    RPG_OPEN_CHEST("RPG Open Chest", 1.0),
    ATTENTION("Attention", 1.0),
    SELECT("Select", 1.0),
    START_GAME("Start Game", 1.0),
    STRUM("Strum", 1.0),
    DINK_DONK("Dink Donk", 1.0),
    TASK_COMPLETED("Task Completed", 1.0),
    BEEP_BOOP("Beep Boop", 1.0),
    BRIGHT_BELL("Bright Bell", 1.0),
    WAZOOP("Wazoop", 1.0),
    CHIME("Chime", 1.0),
    PAGE_FORWARD_CHIME("Page Forward Chime", 1.0),
    GO_BACK("Go Back", 1.0),
    PICKED_COIN_ECHO("Picked Coin Echo", 1.0),
    ICE_AND_CHILI("Ice and Chili", 1.0),
    STOP_BLUE("Stop Blue", 1.0),
    CALL_YOU("Call You", 1.0),
    HOLD_ME_BACK("Hold Me Back", 1.0),
    SLOW_WEEK("Slow Week", 1.0);

    private final String resourceName;
    private final double versionNumber;

    Sound(String resNam, double versionNum) {
        resourceName = resNam;
        versionNumber = versionNum;
    }

    String getResourceName() {
        return resourceName.replace(' ', '_')+"_v"+versionNumber+".wav";
    }
}

package com.ywcode.resourceareanotifier;

import lombok.extern.slf4j.*;
import okhttp3.*;

import javax.inject.*;
import javax.sound.sampled.*;
import java.awt.*;
import java.io.*;
import java.util.concurrent.*;

//Copyright (c) 2021, m0bilebtw
//Opted to largely use m0bilebtw's SoundEngine/SoundFileManager because sounds so often cause client stutters and this code has been tested quite often plus is easy to repurpose.
//Plus it's (partially) based on RL's code and Llemon has at least looked at closing the clips.

@Singleton
@Slf4j
public class SoundEngine {

    @Inject
    private ScheduledExecutorService executor;

    @Inject
    private OkHttpClient okHttpClient;

    private static final long CLIP_MTIME_UNLOADED = -2;

    private long lastClipMTime = CLIP_MTIME_UNLOADED;
    private Clip clip = null;

    @SuppressWarnings("ResultOfMethodCallIgnored")
    private boolean loadClip(Sound sound) {
        try (InputStream stream = new BufferedInputStream(SoundFileManager.getSoundStream(sound))) { //Potentially check out https://github.com/m0bilebtw/c-engineer-completed/commit/d251b6f790ca9dc1b83c03705225c22eceb793d7 if you want to change this a bit.
            try (AudioInputStream audioInputStream = AudioSystem.getAudioInputStream(stream)) {
                clip.open(audioInputStream); //Liable to error with pulseaudio, works on windows, one user informed that mac works
            }
            return true;
        } catch (UnsupportedAudioFileException e) {
            //Beep when it fails to load the sound
            Toolkit.getDefaultToolkit().beep();
            log.warn("Failed to load Resource Area Notifier sound " + sound + ". Use 16-bit .wav files (not 32-bit) if trying to use custom files. Attempting to delete and re-download the file now.", e);
            //Delete problematic file
            File toDelete = new File(SoundFileManager.getDOWNLOAD_DIR(), sound.getResourceName());
            toDelete.delete();
            //Re-download just deleted file
            executor.submit(() -> {
                SoundFileManager.ensureDownloadDirectoryExists();
                SoundFileManager.downloadAllMissingSounds(okHttpClient);
            });
        } catch (IOException | LineUnavailableException e) {
            Toolkit.getDefaultToolkit().beep(); //Beep if file can't be loaded for some reason
            log.warn("Failed to load Resource Area Notifier sound " + sound, e);
        }
        return false;
    }

    public void playClip(Sound sound) {
        long currentMTime = System.currentTimeMillis(); //Maybe swap to nanoTime at some point?
        if (clip == null || currentMTime != lastClipMTime || !clip.isOpen()) {
            if (clip != null && clip.isOpen()) {
                clip.close();
            }

            try {
                clip = AudioSystem.getClip();
            } catch (LineUnavailableException e) {
                lastClipMTime = CLIP_MTIME_UNLOADED;
                Toolkit.getDefaultToolkit().beep(); //Beep if failed to get the clip
                log.warn("Failed to get clip for Resource Area Notifier sound " + sound, e);
                return;
            }

            lastClipMTime = currentMTime;
            if (!loadClip(sound)) {
                return;
            }
        }

        //User configurable volume
        FloatControl volume = (FloatControl) clip.getControl(FloatControl.Type.MASTER_GAIN);
        float gain = 20f * (float) Math.log10(ResourceAreaNotifierPlugin.getNotificationSoundVolume() / 100f);
        gain = Math.min(gain, volume.getMaximum());
        gain = Math.max(gain, volume.getMinimum());
        volume.setValue(gain);

        //From RuneLite base client Notifier class:
        //Using loop instead of start + setFramePosition prevents the clip
        //from not being played sometimes, presumably a race condition in the
        //underlying line driver
        clip.loop(0);
    }

    //Close so we don't leak memory when shutting down the plugin
    public void close() {
        if (clip != null && clip.isOpen()) {
            clip.close();
        }
    }
}

package com.ywcode.resourceareanotifier;

import lombok.*;
import lombok.extern.slf4j.*;
import net.runelite.client.*;
import okhttp3.*;

import java.io.*;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;

//Copyright (c) 2021, m0bilebtw
//Opted to largely use m0bilebtw's SoundEngine/SoundFileManager because sounds so often cause client stutters and this code has been tested quite often plus is easy to repurpose.

@Slf4j
public abstract class SoundFileManager {

    @Getter
    private static final File DOWNLOAD_DIR = new File(RuneLite.RUNELITE_DIR.getPath() + File.separator + "resource-area-notifier-sounds");
    private static final String DELETE_WARNING_FILENAME = "EXTRA_FILES_WILL_BE_DELETED_BUT_FOLDERS_WILL_REMAIN"; //Warning for in the DOWNLOAD_DIR folder
    private static final File DELETE_WARNING_FILE = new File(DOWNLOAD_DIR, DELETE_WARNING_FILENAME);
    private static final HttpUrl RAW_GITHUB = HttpUrl.parse("https://raw.githubusercontent.com/YvesW/resource-area-notifier/sounds-only");

    @SuppressWarnings("ResultOfMethodCallIgnored")
    public static void ensureDownloadDirectoryExists() {
        if (!DOWNLOAD_DIR.exists()) {
            DOWNLOAD_DIR.mkdirs();
        }
        try {
            DELETE_WARNING_FILE.createNewFile();
        } catch (IOException ignored) {
        }
    }

    public static void downloadAllMissingSounds(final OkHttpClient okHttpClient) {
        //Get set of existing files in our dir - existing sounds will be skipped, unexpected files (not dirs, some sounds depending on config [edit: removed this option for now]) will be deleted
        Set<String> filesPresent = getFilesPresent();

        //Download any sounds that are not yet present but desired
        for (Sound sound : getDesiredSoundList()) {
            String fileNameToDownload = sound.getResourceName();
            if (filesPresent.contains(fileNameToDownload) || fileNameToDownload.equals(Sound.DISABLED.getResourceName())) { //Don't try to download a file called Disabled_v1.0.wav
                filesPresent.remove(fileNameToDownload);
                continue;
            }

            if (RAW_GITHUB == null) {
                //Hush intellij, it's okay, the potential NPE can't hurt you now
                log.error("Resource Area Notifications could not download sounds due to an unexpected null RAW_GITHUB value");
                return;
            }
            HttpUrl soundUrl = RAW_GITHUB.newBuilder().addPathSegment(fileNameToDownload).build();
            Path outputPath = Paths.get(DOWNLOAD_DIR.getPath(), fileNameToDownload);
            okHttpClient.newCall(new Request.Builder().url(soundUrl).build()).enqueue(new Callback() {
                //Even though it doesn't matter because it's submitted to the executorService, I'm using enqueue instead of execute. I hope Ron is proud of me.
                @Override
                public void onFailure(Call call, IOException e) {
                    log.error("Resource Area Notifications could not download sounds (okHttp onFailure)", e);
                }

                @Override
                public void onResponse(Call call, Response response) {
                    if (response.body() != null) {
                        try {
                            Files.copy(new BufferedInputStream(response.body().byteStream()), outputPath, StandardCopyOption.REPLACE_EXISTING);
                        } catch (IOException e) {
                            log.error("Resource Area Notifications could not download sounds (okHttp onResponse)", e);
                        }
                    }
                }
            });
        }

        //filesPresent now contains only files in our directory that weren't desired
        //(e.g. old versions of sounds, now removed files)
        //We now delete them to avoid cluttering up disk space
        //We leave dirs behind (getFilesPresent ignores dirs) as we aren't creating those anyway, so they won't build up over time
        for (String filename : filesPresent) {
            File toDelete = new File(DOWNLOAD_DIR, filename);
            //noinspection ResultOfMethodCallIgnored
            toDelete.delete();
        }
    }

    private static Set<String> getFilesPresent() {
        File[] downloadDirFiles = DOWNLOAD_DIR.listFiles();
        if (downloadDirFiles == null || downloadDirFiles.length == 0) {
            return new HashSet<>();
        }

        return Arrays.stream(downloadDirFiles)
                .filter(file -> !file.isDirectory())
                .map(File::getName)
                .filter(filename -> !DELETE_WARNING_FILENAME.equals(filename))
                .collect(Collectors.toSet());
    }

    private static Set<Sound> getDesiredSoundList() { //Could also filter disabled here probably
        return Arrays.stream(Sound.values())
                .collect(Collectors.toSet());
    }

    public static InputStream getSoundStream(Sound sound) throws FileNotFoundException {
        return new FileInputStream(new File(DOWNLOAD_DIR, sound.getResourceName()));
    }
}

