			{
				//rejoin
				leaveOrJoinButton.setText("Left");
				username.setForeground(Color.ORANGE);
				TimePeriod timePeriod = new TimePeriod(System.currentTimeMillis());
				playerInfo.timePeriods.add(timePeriod);
