    //TODO: potentially test 2x and 0.5 scale in RL configure in the future. To do this, add -Dsun.java2d.uiScale.enabled=true -Dsun.java2d.uiScale=2.0 as VM args (source: RL launcher -> LauncherSettings.java). Something maybe worth testing in the future for automatic resizing and contain in screen! How does this count the pixels? Are the bounds etc 2x as well or still 1x?

    @Override
    public void startUp() throws Exception {
        clientThread.invokeLater(() -> {
            currentGameState = client.getGameState();
        });
        defaultResizableScaling = configManager.getConfiguration("stretchedmode", "scalingFactor", Integer.class); //Default might be set to 50 initially, but will set to its current value on reset at least. PM Can't do this on value initialization because then configManager hasn't been injected yet.
        updateConfig();
        setDefaultConfigSettings();
        keyManager.registerKeyListener(keyListener);

        mouseInputListenerMenubar = new MouseInputListener() {
            @Override
            public void mouseEntered(MouseEvent mouseEvent) {
                mouseInMenuBar = true;
                if (clientAntiDragEnabled) {
                    JFrame topFrameClient = (JFrame) SwingUtilities.getWindowAncestor(client.getCanvas());
                    lastClientPosition = topFrameClient.getLocation();
                    lastMouseMoveMenuBar = System.nanoTime();
                }
            }

            @Override
            public void mouseExited(MouseEvent mouseEvent) {
                mouseInMenuBar = false;
            }

            //These methods are unused but required to be present in a MouseInputListener implementation
            //---------------------------------------------------------------
            @Override
            public void mousePressed(MouseEvent mouseEvent) {
                //This is never procced.
            }

            @Override
            public void mouseReleased(MouseEvent mouseEvent) {
                //This is never procced.
            }

            @Override
            public void mouseClicked(MouseEvent mouseEvent) {
				//This is never procced.
            }

            @Override
            public void mouseDragged(MouseEvent mouseEvent) {
                //This is never procced.
                //If you ever want to use mouseDragged and mouseMoved also add a MouseMotionListener by doing customChromeMenuBar.addMouseMotionListener(mouseInputListenerMenubar);
            }

            @Override
            public void mouseMoved(MouseEvent mouseEvent) {
                //This works while moving the mouse over the menubar, but during dragging, the mouse is not moved. Thus, this is pretty useless for detecting when the client is being dragged.
                //Could technically use this with a boolean to know when the mouse is not dragging (because the mouse is moving), but no proper way to detect when the mouse stops moving and at that point the user can already be dragging the client.
                //If you want to use mouseDragged and mouseMoved also add a MouseMotionListener by doing customChromeMenuBar.addMouseMotionListener(mouseInputListenerMenubar);

                //clientAntiDrag. It is important to run this method before other methods so the position of the client is correct.
                clientAntiDrag(); //Method already checks the config value, so no check is needed here.

                //Run monitorCheck every 1/4th of a tick if the mouse is moving in the menubar/title bar to improve snappiness when dragging the client.
                //A boolean override ensures the code will run while the cursor is in the menubar, and that other method calls are not running too frequently/quickly.
                //Additionally, monitorCheck needs to remain a thing in GameTick and BeforeRender, because people can also move the client using Shift+Win+Arrow key etc. (or with custom chrome off)
                long currentNanoTime = System.nanoTime();
                if (currentNanoTime - lastMouseMoveMenuBarTickLimited > ONE_FOURTH_TICK_IN_NANOSECONDS) {
                    monitorCheck(true);
                    lastMouseMoveMenuBarTickLimited = currentNanoTime;
                }
            }
            //---------------------------------------------------------------
        };

        //Get topFrameClient to get the menubar to add the mouseInputListener to it.
        JFrame topFrameClient = (JFrame) SwingUtilities.getWindowAncestor(client.getCanvas());
        JMenuBar customChromeMenuBar = topFrameClient.getJMenuBar();
        if (customChromeMenuBar != null) { //Prevent NPE in case custom chrome is disabled
            customChromeMenuBar.addMouseListener(mouseInputListenerMenubar);
            customChromeMenuBar.addMouseMotionListener(mouseInputListenerMenubar);
        } else {
            //Custom chrome is disabled
            isCustomChromeEnabled = false;
        }
    }

    @Override
    public void shutDown() throws Exception {
        //Unregister all listeners
        keyManager.unregisterKeyListener(keyListener);
        JFrame topFrameClient = (JFrame) SwingUtilities.getWindowAncestor(client.getCanvas());
        JMenuBar customChromeMenuBar = topFrameClient.getJMenuBar();
        if (isCustomChromeEnabled) { //Prevent NPE in case custom chrome is disabled
            customChromeMenuBar.removeMouseListener(mouseInputListenerMenubar);
            customChromeMenuBar.removeMouseMotionListener(mouseInputListenerMenubar);
        }
    }

    @Subscribe
    public void onConfigChanged(ConfigChanged configChanged) {
        String configGroupChanged = configChanged.getGroup();
        if (configGroupChanged.equals(CONFIG_GROUP_NAME)) {
            updateConfig();
            String configKey = configChanged.getKey();
            String newConfigValue = configChanged.getNewValue() != null ? configChanged.getNewValue() : "null";
            switch (configKey) {
                case "copyAttribute": //Only called when the user changes the config value and hasMonitorChanged
                    copyAttributeToClipboard();
                    break;
                case "copyPosition":
                    if (newConfigValue.equals("true")) {
                        copyPositionToClipboard();
                    }
                    break;
                //Send messages when automatic resizing is changed
                case "autoSize1Attribute":
                case "autoSize2Attribute":
                case "autoSize3Attribute":
                case "autoSize4Attribute":
                case "autoSize5Attribute":
                case "autoSize6Attribute":
                case "autoSize7Attribute":
                case "autoSize8Attribute":
                case "autoSize9Attribute":
                case "autoSize10Attribute":
                    if (!newConfigValue.equals("Disabled")) {
                        checkChromeLockSettings();
                    }
                    break;
                //Send messages when contain in screen is changed
                case "containInScreenTop":
                case "containInScreenRight":
                case "containInScreenBottom":
                case "containInScreenLeft":
                    if (newConfigValue.equals("true")) {
                        checkChromeLockSettings();
                    }
                    break;
                //Set the lastClientPosition and lastMouseMoveMenuBar in case the user enables the option with space bar while the cursor is in the menubar.
                case "clientAntiDragEnabled":
                    JFrame topFrameClient = (JFrame) SwingUtilities.getWindowAncestor(client.getCanvas());
                    lastClientPosition = topFrameClient.getLocation();
                    lastMouseMoveMenuBar = System.nanoTime();
                    //Send message when client anti-drag gets enabled but custom chrome is disabled
                    if (newConfigValue.equals("true")) {
                        checkChromeSettings();
                    }
                    break;
            }
        }
        if (configGroupChanged.equals("runelite")) {
            String configKey = configChanged.getKey();
            String newConfigValue = configChanged.getNewValue() != null ? configChanged.getNewValue() : "null";
            switch (configKey) {
                case "uiEnableCustomChrome":
                    checkAutomaticResizeContainAntiDragSettings(configKey, newConfigValue); //already checks is newConfigValue == "false"
                    break;
                case "lockWindowSize":
                    checkAutomaticResizeContainAntiDragSettings(configKey, newConfigValue);
                    setDraggingEdgesWorkaround(newConfigValue);
                    break;
                    //Could technically remove the break and remove the superfluous code here, but too high of a risk that I forget about the missing break in the future.
            }
        }
    }

