		if (config.category() == RunCategory.CUSTOM)
		{
			// Only overwrite if string looks valid
			if (parseWaveTimesFromString(config.getDesiredWaveTimes()).length == 10)
			{
				waveGoal = parseWaveTimesFromString((config.getDesiredWaveTimes()));
			}
		}

		log.debug("Startup");
	}

