	public void chooseSlot(KitType slot)
	{
		PanelEquipSlot panelSlot = Arrays.stream(PanelEquipSlot.values())
			.filter(p -> p.getKitType() == slot)
			.findFirst()
			.orElse(PanelEquipSlot.ALL);
