	private enum TobRoom
	{
		MAIDEN(12613),
		BLOAT(13125),
		NYLOCAS(13122),
		SOTETSEG(13123),
		XARPUS(12612),
		VERZIK(12611),
		COMPLETE(-1);

		private final int regionId;

		/**
		 * Gets the next room in sequence.
		 */
		public TobRoom next()
		{
			int nextOrdinal = this.ordinal() + 1;
			TobRoom[] values = TobRoom.values();
			if (nextOrdinal >= values.length)
			{
				return COMPLETE;
