	public static final String MESSAGE_SPLIT_SOTETSEG = "Wave 'Sotetseg' (Hard Mode) complete!";
	public static final String MESSAGE_SPLIT_XARPUS = "Wave 'Xarpus' (Hard Mode) complete!";
