@Slf4j
@PluginDescriptor(
	name = "Crab Scouter",
	description = "Crowdsourced Gemstone Crab scouting - shows player counts, health, and location across worlds",
	tags = {"crab", "gemstone", "scouter", "crowdsource"}
)
public class CrabScouterPlugin extends Plugin
{
	private static final int GEMSTONE_CRAB_ID = 14779;
	private static final int CHUNK_NORTH = 4913;
	private static final int CHUNK_WEST = 4911;
	private static final int CHUNK_EAST = 5424;
	private static final String SERVER_URL = "wss://crab-scouter.josephpmccarey.workers.dev";

	@Inject
	private Client client;

	@Inject
	private ClientThread clientThread;

	@Inject
	private ClientToolbar clientToolbar;

	@Inject
	private WorldService worldService;

	@Inject
	private OkHttpClient okHttpClient;

	@Inject
	private Gson gson;

	@Getter
	private final List<WorldData> worldDataList = new CopyOnWriteArrayList<>();

	private CrabScouterPanel panel;
	private NavigationButton navButton;
	private CrabScouterWebSocketClient webSocketClient;

	@Getter
	private boolean isReporter = false;

	@Getter
	private boolean isConnected = false;

	private NPC trackedCrab;
	private int lastHealthRatio = -1;
	private int lastPlayerCount = -1;
	private int currentChunk = -1;
	private boolean inCrabArea = false;
	private int ticksSinceLastReport = 0;
	private int ticksWithoutCrab = 0;

	// World hopping state
	private static final int HOP_MAX_ATTEMPTS = 3;
	private net.runelite.api.World quickHopTargetWorld;
	private int hopAttempts = 0;

	@Override
	protected void startUp() throws Exception
	{
		log.debug("Crab Scouter started!");

		panel = new CrabScouterPanel(this);

		final BufferedImage icon = ImageUtil.loadImageResource(getClass(), "/crab_icon.png");
		navButton = NavigationButton.builder()
			.tooltip("Crab Scouter")
			.icon(icon != null ? icon : new BufferedImage(16, 16, BufferedImage.TYPE_INT_ARGB))
			.priority(10)
			.panel(panel)
			.build();

		clientToolbar.addNavigation(navButton);

		webSocketClient = new CrabScouterWebSocketClient(this, SERVER_URL, okHttpClient, gson);
		webSocketClient.connect();
	}

	@Override
	protected void shutDown() throws Exception
	{
		log.debug("Crab Scouter stopped!");

		if (inCrabArea && webSocketClient != null)
		{
			webSocketClient.sendLeave(client.getWorld());
		}

		if (webSocketClient != null)
		{
			webSocketClient.close();
			webSocketClient = null;
		}

		clientToolbar.removeNavigation(navButton);
		panel = null;
		navButton = null;

		trackedCrab = null;
		inCrabArea = false;
		isReporter = false;
		isConnected = false;
	}

	@Subscribe
	public void onGameStateChanged(GameStateChanged event)
	{
		if (event.getGameState() == GameState.LOGIN_SCREEN || event.getGameState() == GameState.HOPPING)
		{
			if (inCrabArea && webSocketClient != null)
			{
				webSocketClient.sendLeave(client.getWorld());
			}
			inCrabArea = false;
			trackedCrab = null;
			isReporter = false;
			currentChunk = -1;
		}
	}

	@Subscribe
	public void onGameTick(GameTick event)
	{
		handleHop();

		if (client.getGameState() != GameState.LOGGED_IN)
		{
			return;
		}

		WorldPoint playerLocation = client.getLocalPlayer().getWorldLocation();
		int regionId = playerLocation.getRegionID();

		if (ticksSinceLastReport % 10 == 0)
		{
			log.debug("Player at region {} (x={}, y={})", regionId, playerLocation.getX(), playerLocation.getY());
		}

		boolean wasInCrabArea = inCrabArea;
		inCrabArea = (regionId == CHUNK_NORTH || regionId == CHUNK_WEST || regionId == CHUNK_EAST);
		currentChunk = inCrabArea ? regionId : -1;

		if (inCrabArea && !wasInCrabArea)
		{
			onEnterCrabArea();
		}
		else if (!inCrabArea && wasInCrabArea)
		{
			onLeaveCrabArea();
		}

		if (inCrabArea && isReporter)
		{
			ticksSinceLastReport++;
			checkAndReport();
		}
		else
		{
			ticksSinceLastReport++;
		}
	}

	private void onEnterCrabArea()
	{
		log.debug("Entered crab area in chunk {}", currentChunk);
		if (isPvpWorld())
		{
			log.debug("Skipping join - PvP world");
			return;
		}
		if (webSocketClient != null)
		{
			webSocketClient.sendJoin(client.getWorld(), currentChunk);
		}
		findCrab();
	}

	private boolean isPvpWorld()
	{
		WorldResult worldResult = worldService.getWorlds();
		if (worldResult == null)
		{
			return false;
		}

		World world = worldResult.findWorld(client.getWorld());
		if (world == null)
		{
			return false;
		}

		return world.getTypes().contains(WorldType.PVP)
			|| world.getTypes().contains(WorldType.HIGH_RISK)
			|| world.getTypes().contains(WorldType.DEADMAN);
	}

	private void onLeaveCrabArea()
	{
		log.debug("Left crab area");
		if (webSocketClient != null)
		{
			webSocketClient.sendLeave(client.getWorld());
		}
		trackedCrab = null;
		isReporter = false;
		lastHealthRatio = -1;
		lastPlayerCount = -1;
		ticksSinceLastReport = 0;
	}

	@Subscribe
	public void onNpcSpawned(NpcSpawned event)
	{
		if (!inCrabArea)
		{
			return;
		}

		NPC npc = event.getNpc();
		if (npc.getId() == GEMSTONE_CRAB_ID)
		{
			trackedCrab = npc;
			log.debug("Gemstone crab spawned by ID: {}", npc.getId());
			return;
		}

		String name = npc.getName();
		if (name != null && isGemstoneCrab(name))
		{
			trackedCrab = npc;
			log.debug("Gemstone crab spawned by name: {} (ID: {})", name, npc.getId());
		}
	}

	private boolean isGemstoneCrab(String name)
	{
		String lower = name.toLowerCase();
		return lower.contains("gemstone") && lower.contains("crab") && !lower.contains("shell");
	}

	@Subscribe
	public void onNpcDespawned(NpcDespawned event)
	{
		if (trackedCrab != null && event.getNpc() == trackedCrab)
		{
			trackedCrab = null;
			log.debug("Gemstone crab despawned");
		}
	}

	private void findCrab()
	{
		WorldView worldView = client.getTopLevelWorldView();
		if (worldView == null)
		{
			return;
		}

		int npcCount = 0;
		for (NPC npc : worldView.npcs())
		{
			npcCount++;
			if (npc.getId() == GEMSTONE_CRAB_ID)
			{
				trackedCrab = npc;
				log.debug("Found gemstone crab by ID: {}", npc.getId());
				return;
			}

			String name = npc.getName();
			if (name != null && isGemstoneCrab(name))
			{
				trackedCrab = npc;
				log.debug("Found gemstone crab by name: {} (ID: {})", name, npc.getId());
				return;
			}
		}

		log.debug("Gemstone crab not found in {} NPCs", npcCount);
	}

	private void checkAndReport()
	{
		if (!isReporter || webSocketClient == null || currentChunk == -1 || isPvpWorld())
		{
			return;
		}

		if (trackedCrab == null)
		{
			findCrab();
		}

		if (trackedCrab == null)
		{
			ticksWithoutCrab++;
			if (ticksWithoutCrab >= 50)
			{
				log.debug("Can't see crab for {} ticks, resigning as reporter", ticksWithoutCrab);
				webSocketClient.sendResign(client.getWorld());
				isReporter = false;
				ticksWithoutCrab = 0;
			}
			return;
		}

		ticksWithoutCrab = 0;

		int crabChunk = trackedCrab.getWorldLocation().getRegionID();
		if (crabChunk != currentChunk)
		{
			log.debug("Crab is in different chunk ({}) than player ({})", crabChunk, currentChunk);
			trackedCrab = null;
			return;
		}

		int currentHealth = getHealthPercent();
		int[] playerCounts = countPlayers();
		int totalPlayers = playerCounts[0];
		int attackingPlayers = playerCounts[1];

		boolean healthChanged = Math.abs(currentHealth - lastHealthRatio) > 5;
		boolean playersChanged = totalPlayers != lastPlayerCount;
		boolean heartbeat = ticksSinceLastReport >= 100;

		if (healthChanged || playersChanged || heartbeat)
		{
			log.debug("Sending report: world={}, chunk={}, health={}, total={}, attacking={}, reason={}",
				client.getWorld(), crabChunk, currentHealth, totalPlayers, attackingPlayers,
				heartbeat ? "heartbeat" : (healthChanged ? "health" : "players"));
			webSocketClient.sendReport(client.getWorld(), crabChunk, currentHealth, totalPlayers, attackingPlayers);
			lastHealthRatio = currentHealth;
			lastPlayerCount = totalPlayers;
			ticksSinceLastReport = 0;
		}
	}

	private int getHealthPercent()
	{
		if (trackedCrab == null)
		{
			log.debug("getHealthPercent: trackedCrab is null");
			return 100;
		}

		int ratio = trackedCrab.getHealthRatio();
		int scale = trackedCrab.getHealthScale();

		log.debug("getHealthPercent: ratio={}, scale={}", ratio, scale);

		if (ratio == -1 || scale == -1)
		{
			return 100;
		}

		return (int) ((ratio / (double) scale) * 100);
	}

	private int[] countPlayers()
	{
		int totalPlayers = 0;
		int attackingPlayers = 0;

		WorldView worldView = client.getTopLevelWorldView();
		if (worldView == null)
		{
			return new int[]{0, 0};
		}

		for (Player player : worldView.players())
		{
			if (player == null)
			{
				continue;
			}

			totalPlayers++;

			if (trackedCrab != null)
			{
				Actor target = player.getInteracting();
				if (target == trackedCrab)
				{
					attackingPlayers++;
				}
			}
		}

		log.debug("countPlayers: total={}, attacking={}", totalPlayers, attackingPlayers);

		return new int[]{totalPlayers, attackingPlayers};
	}

	public void onWebSocketConnected()
	{
		isConnected = true;
		log.debug("WebSocket connected");
		updatePanel();

		clientThread.invokeLater(() ->
		{
			if (inCrabArea && client.getGameState() == GameState.LOGGED_IN && !isPvpWorld())
			{
				log.debug("Reconnected while in crab area, resending join");
				webSocketClient.sendJoin(client.getWorld(), currentChunk);
			}
		});
	}

	public void onWebSocketDisconnected()
	{
		isConnected = false;
		isReporter = false;
		log.debug("WebSocket disconnected");
		updatePanel();
	}

	public void onRoleAssigned(boolean reporter)
	{
		isReporter = reporter;
		log.debug("Role assigned: {}", reporter ? "reporter" : "listener");

		if (isReporter && inCrabArea && !isPvpWorld())
		{
			clientThread.invokeLater(() ->
			{
				int currentHealth = getHealthPercent();
				int[] playerCounts = countPlayers();
				webSocketClient.sendReport(client.getWorld(), currentChunk, currentHealth, playerCounts[0], playerCounts[1]);
				lastHealthRatio = currentHealth;
				lastPlayerCount = playerCounts[0];
				ticksSinceLastReport = 0;
			});
		}
	}

	public void onWorldsUpdate(List<WorldData> worlds)
	{
		log.debug("onWorldsUpdate called with {} worlds", worlds.size());
		worldDataList.clear();
		worldDataList.addAll(worlds);
		updatePanel();
	}

	private void updatePanel()
	{
		log.debug("updatePanel called, panel={}, worldDataList size={}", panel != null, worldDataList.size());
		if (panel != null)
		{
			SwingUtilities.invokeLater(panel::update);
		}
	}

	public void hopToWorld(int worldNumber)
	{
		log.debug("hopToWorld called for world {}", worldNumber);

		if (client.getGameState() != GameState.LOGGED_IN)
		{
			log.warn("Cannot hop - not logged in (state: {})", client.getGameState());
			return;
		}

		int currentWorld = client.getWorld();
		if (currentWorld == worldNumber)
		{
			log.debug("Already on world {}", worldNumber);
			return;
		}

		WorldResult worldResult = worldService.getWorlds();
		if (worldResult == null)
		{
			log.warn("World list not loaded yet");
			return;
		}

		World targetWorld = worldResult.findWorld(worldNumber);
		if (targetWorld == null)
		{
			log.warn("Could not find world {} in world list", worldNumber);
			return;
		}

		log.info("Hopping to world {} (current: {})", worldNumber, currentWorld);
		net.runelite.api.World rsWorld = client.createWorld();
		rsWorld.setActivity(targetWorld.getActivity());
		rsWorld.setAddress(targetWorld.getAddress());
		rsWorld.setId(targetWorld.getId());
		rsWorld.setPlayerCount(targetWorld.getPlayers());
		rsWorld.setLocation(targetWorld.getLocation());
		rsWorld.setTypes(WorldUtil.toWorldTypes(targetWorld.getTypes()));

		// Set target world - actual hop happens in handleHop() on game tick
		quickHopTargetWorld = rsWorld;
		hopAttempts = 0;
	}

	private void handleHop()
	{
		if (quickHopTargetWorld == null)
		{
			return;
		}

		// Check if world switcher is open
		if (client.getWidget(ComponentID.WORLD_SWITCHER_WORLD_LIST) == null)
		{
			// Open the world hopper first
			client.openWorldHopper();

			if (++hopAttempts >= HOP_MAX_ATTEMPTS)
			{
				log.warn("Failed to open world switcher after {} attempts", hopAttempts);
				resetHop();
			}
		}
		else
		{
			// World switcher is open, perform the hop
			client.hopToWorld(quickHopTargetWorld);
			resetHop();
		}
	}

	private void resetHop()
	{
		quickHopTargetWorld = null;
		hopAttempts = 0;
	}
}

package com.crabscouter;

import java.awt.BorderLayout;
import java.awt.Color;
import java.awt.Cursor;
import java.awt.Dimension;
import java.awt.GridLayout;
import javax.swing.Box;
import javax.swing.BoxLayout;
import java.awt.event.MouseAdapter;
import java.awt.event.MouseEvent;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import javax.swing.BorderFactory;
import javax.swing.JLabel;
import javax.swing.JPanel;
import javax.swing.JScrollPane;
import javax.swing.SwingConstants;
import javax.swing.border.EmptyBorder;
import net.runelite.client.ui.ColorScheme;
import net.runelite.client.ui.FontManager;
import net.runelite.client.ui.PluginPanel;

public class CrabScouterPanel extends PluginPanel
{
	private enum SortColumn
	{
		WORLD, CHUNK, HEALTH, PLAYERS
	}

	private final CrabScouterPlugin plugin;
	private final JPanel worldListPanel;
	private final JLabel statusLabel;
	private final JLabel roleLabel;
	private final JLabel connectionIndicator;
	private final JLabel[] headerLabels = new JLabel[4];

	private SortColumn sortColumn = SortColumn.WORLD;
	private boolean sortAscending = true;

	public CrabScouterPanel(CrabScouterPlugin plugin)
	{
		super(false);
		this.plugin = plugin;

		setLayout(new BorderLayout());
		setBackground(ColorScheme.DARK_GRAY_COLOR);
		setBorder(new EmptyBorder(10, 10, 10, 10));

		JPanel headerPanel = new JPanel(new BorderLayout());
		headerPanel.setBackground(ColorScheme.DARK_GRAY_COLOR);
		headerPanel.setBorder(new EmptyBorder(0, 0, 10, 0));

		JLabel titleLabel = new JLabel("Crab Scouter");
		titleLabel.setFont(FontManager.getRunescapeBoldFont());
		titleLabel.setForeground(Color.WHITE);

		connectionIndicator = new JLabel("●");
		connectionIndicator.setForeground(Color.RED);
		connectionIndicator.setFont(FontManager.getRunescapeBoldFont());

		JPanel titleRow = new JPanel(new BorderLayout());
		titleRow.setBackground(ColorScheme.DARK_GRAY_COLOR);
		titleRow.setBorder(new EmptyBorder(0, 0, 8, 0));
		titleRow.add(titleLabel, BorderLayout.WEST);
		titleRow.add(connectionIndicator, BorderLayout.EAST);

		headerPanel.add(titleRow, BorderLayout.NORTH);

		JPanel columnHeaders = createHeaderRow();
		headerPanel.add(columnHeaders, BorderLayout.SOUTH);

		add(headerPanel, BorderLayout.NORTH);

		worldListPanel = new JPanel();
		worldListPanel.setLayout(new BoxLayout(worldListPanel, BoxLayout.Y_AXIS));
		worldListPanel.setBackground(ColorScheme.DARK_GRAY_COLOR);

		JScrollPane scrollPane = new JScrollPane(worldListPanel);
		scrollPane.setBackground(ColorScheme.DARK_GRAY_COLOR);
		scrollPane.setBorder(BorderFactory.createEmptyBorder());
		scrollPane.getVerticalScrollBar().setPreferredSize(new Dimension(8, 0));

		add(scrollPane, BorderLayout.CENTER);

		JPanel footerPanel = new JPanel(new BorderLayout());
		footerPanel.setBackground(ColorScheme.DARK_GRAY_COLOR);
		footerPanel.setBorder(new EmptyBorder(10, 0, 0, 0));

		statusLabel = new JLabel("Connecting...");
		statusLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
		statusLabel.setFont(FontManager.getRunescapeSmallFont());
		footerPanel.add(statusLabel, BorderLayout.WEST);

		roleLabel = new JLabel("");
		roleLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
		roleLabel.setFont(FontManager.getRunescapeSmallFont());
		footerPanel.add(roleLabel, BorderLayout.SOUTH);

		add(footerPanel, BorderLayout.SOUTH);

		update();
	}

	private JPanel createHeaderRow()
	{
		JPanel row = new JPanel(new GridLayout(1, 4, 5, 1));
		row.setBackground(ColorScheme.DARKER_GRAY_COLOR);
		row.setBorder(new EmptyBorder(5, 5, 5, 5));

		headerLabels[0] = createSortableHeaderLabel("World", SortColumn.WORLD);
		headerLabels[1] = createSortableHeaderLabel("Chunk", SortColumn.CHUNK);
		headerLabels[2] = createSortableHeaderLabel("HP", SortColumn.HEALTH);
		headerLabels[3] = createSortableHeaderLabel("#", SortColumn.PLAYERS);

		for (JLabel label : headerLabels)
		{
			row.add(label);
		}

		updateHeaderLabels();
		return row;
	}

	private JLabel createSortableHeaderLabel(String text, SortColumn column)
	{
		JLabel label = new JLabel(text, SwingConstants.CENTER);
		label.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
		label.setFont(FontManager.getRunescapeSmallFont());
		label.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
		label.putClientProperty("column", column);
		label.putClientProperty("baseText", text);

		label.addMouseListener(new MouseAdapter()
		{
			@Override
			public void mouseClicked(MouseEvent e)
			{
				onHeaderClick(column);
			}

			@Override
			public void mouseEntered(MouseEvent e)
			{
				label.setForeground(Color.WHITE);
			}

			@Override
			public void mouseExited(MouseEvent e)
			{
				label.setForeground(column == sortColumn ? Color.WHITE : ColorScheme.LIGHT_GRAY_COLOR);
			}
		});

		return label;
	}

	private void onHeaderClick(SortColumn column)
	{
		if (sortColumn == column)
		{
			sortAscending = !sortAscending;
		}
		else
		{
			sortColumn = column;
			sortAscending = true;
		}
		updateHeaderLabels();
		update();
	}

	private void updateHeaderLabels()
	{
		String[] baseTexts = {"World", "Chunk", "HP", "#"};
		SortColumn[] columns = {SortColumn.WORLD, SortColumn.CHUNK, SortColumn.HEALTH, SortColumn.PLAYERS};

		for (int i = 0; i < headerLabels.length; i++)
		{
			String text = baseTexts[i];
			if (columns[i] == sortColumn)
			{
				text += sortAscending ? " ↑" : " ↓";
				headerLabels[i].setForeground(Color.WHITE);
			}
			else
			{
				headerLabels[i].setForeground(ColorScheme.LIGHT_GRAY_COLOR);
			}
			headerLabels[i].setText(text);
		}
	}

	private List<WorldData> getSortedWorlds(List<WorldData> worlds)
	{
		List<WorldData> sorted = new ArrayList<>();
		for (WorldData data : worlds)
		{
			if (data.isFresh())
			{
				sorted.add(data);
			}
		}

		Comparator<WorldData> comparator;
		switch (sortColumn)
		{
			case CHUNK:
				comparator = Comparator.comparing(WorldData::getChunkName);
				break;
			case HEALTH:
				comparator = Comparator.comparingInt(WorldData::getHealth);
				break;
			case PLAYERS:
				comparator = Comparator.comparingInt(WorldData::getTotalPlayers);
				break;
			case WORLD:
			default:
				comparator = Comparator.comparingInt(WorldData::getWorld);
				break;
		}

		if (!sortAscending)
		{
			comparator = comparator.reversed();
		}

		sorted.sort(comparator);
		return sorted;
	}

	public void update()
	{
		worldListPanel.removeAll();

		boolean connected = plugin.isConnected();
		connectionIndicator.setForeground(connected ? Color.GREEN : Color.RED);
		connectionIndicator.setToolTipText(connected ? "Connected" : "Disconnected");

		List<WorldData> worlds = plugin.getWorldDataList();
		List<WorldData> sortedWorlds = getSortedWorlds(worlds);

		if (worlds.isEmpty())
		{
			JLabel emptyLabel = new JLabel("No crab data available");
			emptyLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
			emptyLabel.setAlignmentX(CENTER_ALIGNMENT);
			worldListPanel.add(Box.createVerticalGlue());
			worldListPanel.add(emptyLabel);
			worldListPanel.add(Box.createVerticalGlue());
		}
		else if (sortedWorlds.isEmpty())
		{
			JLabel staleLabel = new JLabel("All data stale");
			staleLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);
			staleLabel.setAlignmentX(CENTER_ALIGNMENT);
			worldListPanel.add(Box.createVerticalGlue());
			worldListPanel.add(staleLabel);
			worldListPanel.add(Box.createVerticalGlue());
		}
		else
		{
			for (WorldData data : sortedWorlds)
			{
				worldListPanel.add(createWorldRow(data));
			}
		}

		int scoutCount = worlds.size();
		StringBuilder status = new StringBuilder();
		if (scoutCount == 0)
		{
			status.append("No worlds are reporting data");
		}
		else
		{
			status.append(scoutCount)
				.append(scoutCount == 1 ? " world is" : " worlds are")
				.append(" reporting data");
		}
		statusLabel.setText(status.toString());
		roleLabel.setText(plugin.isReporter() ? "You are reporting for your world." : "");	

		revalidate();
		repaint();
	}

	private JPanel createWorldRow(WorldData data)
	{
		JPanel row = new JPanel(new GridLayout(1, 4, 5, 0));
		row.setBackground(ColorScheme.DARKER_GRAY_COLOR);
		row.setBorder(new EmptyBorder(4, 5, 4, 5));
		row.setCursor(Cursor.getPredefinedCursor(Cursor.HAND_CURSOR));
		row.setMaximumSize(new Dimension(Integer.MAX_VALUE, 24));

		JLabel worldLabel = new JLabel(String.valueOf(data.getWorld()), SwingConstants.CENTER);
		worldLabel.setForeground(Color.WHITE);

		JLabel chunkLabel = new JLabel(data.getChunkName(), SwingConstants.CENTER);
		chunkLabel.setForeground(ColorScheme.LIGHT_GRAY_COLOR);

		JLabel healthLabel = new JLabel(data.getHealth() + "%", SwingConstants.CENTER);
		healthLabel.setForeground(getHealthColor(data.getHealth()));

		String playerText = data.getAttackingPlayers() + "/" + data.getTotalPlayers();
		JLabel playersLabel = new JLabel(playerText, SwingConstants.CENTER);
		playersLabel.setForeground(getPlayerCountColor(data.getTotalPlayers()));
		playersLabel.setToolTipText(data.getAttackingPlayers() + " attacking, " + data.getTotalPlayers() + " total");

		row.add(worldLabel);
		row.add(chunkLabel);
		row.add(healthLabel);
		row.add(playersLabel);

		row.addMouseListener(new MouseAdapter()
		{
			@Override
			public void mouseClicked(MouseEvent e)
			{
				if (e.getClickCount() == 2)
				{
					plugin.hopToWorld(data.getWorld());
				}
			}

			@Override
			public void mouseEntered(MouseEvent e)
			{
				row.setBackground(ColorScheme.DARKER_GRAY_HOVER_COLOR);
			}

			@Override
			public void mouseExited(MouseEvent e)
			{
				row.setBackground(ColorScheme.DARKER_GRAY_COLOR);
			}
		});

		return row;
	}

	private Color getHealthColor(int health)
	{
		if (health > 66)
		{
			return Color.GREEN;
		}
		else if (health > 33)
		{
			return Color.YELLOW;
		}
		else
		{
			return Color.RED;
		}
	}

	private Color getPlayerCountColor(int count)
	{
		if (count <= 5)
		{
			return Color.GREEN;
		}
		else if (count <= 15)
		{
			return Color.YELLOW;
		}
		else
		{
			return Color.ORANGE;
		}
	}
}

