package com.bindingnecklacereminder;

import com.google.inject.Provides;
import javax.inject.Inject;
import lombok.extern.slf4j.Slf4j;
import net.runelite.api.Client;
import net.runelite.api.GameState;
import net.runelite.api.ItemContainer;
import net.runelite.api.events.ChatMessage;
import net.runelite.api.events.ItemContainerChanged;
import net.runelite.api.events.VarbitChanged;
import net.runelite.api.gameval.InventoryID;
import net.runelite.api.gameval.ItemID;
import net.runelite.api.gameval.VarPlayerID;
import net.runelite.client.callback.ClientThread;
import net.runelite.client.config.ConfigManager;
import net.runelite.client.eventbus.Subscribe;
import net.runelite.client.events.ConfigChanged;
import net.runelite.client.plugins.Plugin;
import net.runelite.client.plugins.PluginDescriptor;
import net.runelite.client.ui.overlay.OverlayManager;
import net.runelite.client.util.Text;

@Slf4j
@PluginDescriptor(
	name = "Binding Necklace Reminder"
)
public class BindingNecklaceReminderPlugin extends Plugin
{
	@Inject
	private Client client;

	@Inject
	private ClientThread clientThread;

	@Inject
	private ConfigManager configManager;

	@Inject
	private OverlayManager overlayManager;

	@Inject
	private BindingNecklaceReminderOverlay overlay;

	@Inject
	private BindingNecklaceReminderConfig config;

	@Override
	protected void startUp() throws Exception
	{
		if (client.getGameState() == GameState.LOGGED_IN)
		{
			clientThread.invokeLater(this::checkCharge);
		}
	}

	@Override
	protected void shutDown() throws Exception
	{
		overlayManager.remove(overlay);
	}

	@Subscribe
	private void onConfigChanged(ConfigChanged event)
	{
		if (client.getGameState() == GameState.LOGGED_IN)
		{
			clientThread.invokeLater(this::checkCharge);
		}
	}

	@Subscribe
	private void onItemContainerChanged(ItemContainerChanged event)
	{
		if (event.getContainerId() != InventoryID.WORN && event.getContainerId() != InventoryID.INV)
		{
			return;
		}

		checkCharge();
	}

	@Subscribe
	private void onVarbitChanged(VarbitChanged event)
	{
		if (event.getVarpId() == VarPlayerID.NECKLACE_OF_BINDING)
		{
			setCharge(event.getValue());
			checkCharge();
		}
	}

	@Subscribe
	private void onChatMessage(ChatMessage event)
	{
		String message = Text.removeTags(event.getMessage());
		if (message.contains("Your Binding necklace has disintegrated."))
		{
			setCharge(16);
		}
	}

	private void setCharge(int value)
	{
		configManager.setRSProfileConfiguration(BindingNecklaceReminderConfig.GROUP, "bindingNecklace", value);
	}

	public int getCharge()
	{
		Integer charge = configManager.getRSProfileConfiguration(BindingNecklaceReminderConfig.GROUP, "bindingNecklace", Integer.class);
		return charge == null ? 0 : charge;
	}

	private void checkCharge()
	{
		final ItemContainer equipment = client.getItemContainer(InventoryID.WORN);
		final ItemContainer inventory = client.getItemContainer(InventoryID.INV);
		if ((equipment != null && equipment.contains(ItemID.MAGIC_EMERALD_NECKLACE)) ||
			(inventory != null && inventory.contains(ItemID.MAGIC_EMERALD_NECKLACE)))
		{
			int charge = getCharge();

			if (charge <= config.chargeThreshold())
			{
				overlayManager.add(overlay);
			}
			else
			{
				overlayManager.remove(overlay);
			}
		}
		else
		{
			overlayManager.remove(overlay);
		}
	}

	@Provides
	BindingNecklaceReminderConfig provideConfig(ConfigManager configManager)
	{
		return configManager.getConfig(BindingNecklaceReminderConfig.class);
	}
}

package com.bindingnecklacereminder;

import java.awt.Color;
import java.awt.Font;
import lombok.Getter;
import lombok.RequiredArgsConstructor;
import net.runelite.client.config.Alpha;
import net.runelite.client.config.Config;
import net.runelite.client.config.ConfigGroup;
import net.runelite.client.config.ConfigItem;
import net.runelite.client.config.Range;
import net.runelite.client.ui.FontManager;

@ConfigGroup(BindingNecklaceReminderConfig.GROUP)
public interface BindingNecklaceReminderConfig extends Config
{
	String GROUP = "bindingNecklaceReminder";

	@Range(
		max = 16
	)
	@ConfigItem(
		keyName = "chargeThreshold",
		name = "Charge Threshold",
		description = "Draw overlay when binding necklace charges are at or below this value (0 to disable)"
	)
	default int chargeThreshold()
	{
		return 4;
	}

	@ConfigItem(
		keyName = "overlayFont",
		name = "Overlay Font",
		description = "Set the font for the text drawn in the overlay"
	)
	default Fonts overlayFont()
	{
		return Fonts.REGULAR;
	}

	@Alpha
	@ConfigItem(
		keyName = "overlayColour",
		name = "Overlay Colour",
		description = "Set the colour for the overlay background"
	)
	default Color overlayColour()
	{
		return new Color(255, 0, 0, 150);
	}

	@Getter
	@RequiredArgsConstructor
	enum Fonts
	{
		SMALL(FontManager.getRunescapeSmallFont()),
		REGULAR(FontManager.getRunescapeFont()),
		BOLD(FontManager.getRunescapeBoldFont());

		private final Font font;
	}
}

package com.bindingnecklacereminder;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.Graphics2D;
import javax.inject.Inject;
import net.runelite.api.Client;
import net.runelite.client.ui.overlay.OverlayPanel;
import net.runelite.client.ui.overlay.OverlayPosition;
import net.runelite.client.ui.overlay.components.TitleComponent;

public class BindingNecklaceReminderOverlay extends OverlayPanel
{
	private final BindingNecklaceReminderPlugin plugin;
	private final BindingNecklaceReminderConfig config;

	@Inject
	private BindingNecklaceReminderOverlay(Client client, BindingNecklaceReminderPlugin plugin, BindingNecklaceReminderConfig config)
	{
		this.plugin = plugin;
		this.config = config;
	}

	@Override
	public Dimension render(Graphics2D graphics2D)
	{
		panelComponent.getChildren().clear();
		panelComponent.getChildren().add(
			TitleComponent.builder()
			.text("Binding Necklace")
			.color(Color.WHITE)
			.build()
		);
		panelComponent.getChildren().add(
			TitleComponent.builder()
			.text("Charges: " + plugin.getCharge())
			.color(Color.WHITE)
			.build()
		);
		panelComponent.setBackgroundColor(config.overlayColour());
		graphics2D.setFont(config.overlayFont().getFont());
		setPosition(OverlayPosition.ABOVE_CHATBOX_RIGHT);

		return panelComponent.render(graphics2D);
	}
}

